#include <stdio.h>
#include <string.h>
#define BASE 100007
#define MOD 264
int is_palindrome(const char *s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) return 0;
        ++l; --r;
    }
    return 1;
}
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    char buf[105];
    while (T--) {
        scanf("%s", buf);
        int n = strlen(buf);
        long long ans = 0;
        for (int len = 1; len <= n; ++len) {
            int k = 0; // 0 means not found yet
            for (int start = 0; start + len <= n; ++start) {
                if (!is_palindrome(buf, start, start + len - 1)) {
                    k = start + 1; // convert to 1-based
                    break;
                }
            }
            ans = (ans * BASE + k) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

