import java.io.*;
import java.util.*;
public class Main {
    static final long BASE = 100007L;
    static final long MOD = 264L;
    static boolean isPal(char[] a, int l, int r) {
        while (l < r) {
            if (a[l] != a[r]) return false;
            l++; r--;
        }
        return true;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String s = br.readLine().trim();
            char[] arr = s.toCharArray();
            int n = arr.length;
            long ans = 0;
            for (int len = 1; len <= n; ++len) {
                int k = 0;
                for (int st = 0; st + len <= n; ++st) {
                    if (!isPal(arr, st, st + len - 1)) { k = st + 1; break; }
                }
                ans = (ans * BASE + k) % MOD;
            }
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys
BASE = 100007
MOD = 264
def is_pal(s, l, r):
    while l < r:
        if s[l] != s[r]:
            return False
        l += 1
        r -= 1
    return True
def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        s = data[i].strip()
        n = len(s)
        ans = 0
        for length in range(1, n+1):
            k = 0
            for start in range(0, n-length+1):
                if not is_pal(s, start, start+length-1):
                    k = start + 1  # 1-based
                    break
            ans = (ans * BASE + k) % MOD
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

